import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.intellij_idea
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_STYLE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.ec4j.core.model.PropertyType
import org.junit.jupiter.api.Test

internal class IndentationRuleLambdaParametersInTrailingLambdaTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given trailing lambda with parameters on multiple lines after multiline call arguments then align the parameters under the first parameter`() {
        val code =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
              c(a, b)
            }

            class Foo {
              fun foo() {
                combine(
                  Any(),
                  Any()
                ) { a,
                    b ->
                  TODO()
                }
              }
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(
                CODE_STYLE_PROPERTY to intellij_idea,
                INDENT_SIZE_PROPERTY to 2,
                INDENT_STYLE_PROPERTY to PropertyType.IndentStyleValue.space,
            ).hasNoLintViolations()
    }
}
